#include <stdio.h>
#include <stdint.h>

static int trailing_nines(int64_t n) {
    int cnt = 0;
    while (n % 10 == 9) {
        cnt++;
        n /= 10;
    }
    return cnt;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t N;
        scanf("%lld", &N);
        int k = trailing_nines(N);
        int64_t ans = (k % 2 == 0) ? N + 1 : N + 2;
        printf("%lld\n", ans);
    }
    return 0;
}

